    from sanic import Sanic


class AltSvcCheck(BaseScheme):
    ident = "ALTSVC"

    def visitors(self) -> list[NodeTransformer]:
        return [RemoveAltSvc(self.app, self.app.state.verbosity)]


class RemoveAltSvc(NodeTransformer):
    def __init__(self, app: Sanic, verbosity: int = 0) -> None:
        self._app = app
        self._verbosity = verbosity
        self._versions = {
            info.settings["version"] for info in app.state.server_info
        }

    def visit_Assign(self, node: Assign) -> Any:
        if any(self._matches(target) for target in node.targets):
            if self._should_remove():
                return None
            assert isinstance(node.value, Constant)
            node.value.value = self.value()
        return node

    def _should_remove(self) -> bool:
        return len(self._versions) == 1

    @staticmethod
    def _matches(node) -> bool:
        return (
            isinstance(node, Subscript)
            and isinstance(node.slice, Constant)
            and node.slice.value == "alt-svc"
        )

    def value(self):
        values = []
        for info in self._app.state.server_info:
            port = info.settings["port"]
            version = info.settings["version"]
            if version is HTTP.VERSION_3:
                values.append(f'h3=":{port}"')
        return ", ".join(values)

@classmethod
    def get_backend(cls) -> Backend:
        assert cls._backend, "You must call init first!"  # noqa: S101
        return cls._backend

    @classmethod
    def get_prefix(cls) -> str:
        assert cls._prefix is not None, "You must call init first!"  # noqa: S101
        return cls._prefix

    @classmethod
    def get_expire(cls) -> Optional[int]:
        return cls._expire

    @classmethod
    def get_coder(cls) -> Type[Coder]:
        assert cls._coder, "You must call init first!"  # noqa: S101
        return cls._coder

    @classmethod
    def get_key_builder(cls) -> KeyBuilder:
        assert cls._key_builder, "You must call init first!"  # noqa: S101
        return cls._key_builder

    @classmethod
    def get_cache_status_header(cls) -> str:
        assert cls._cache_status_header, "You must call init first!"  # noqa: S101
        return cls._cache_status_header

    @classmethod
    def get_enable(cls) -> bool:
        return cls._enable

    @classmethod
    async def clear(
        cls, namespace: Optional[str] = None, key: Optional[str] = None
    ) -> int:
        assert (  # noqa: S101
            cls._backend and cls._prefix is not None
        ), "You must call init first!"
        namespace = cls._prefix + (":" + namespace if namespace else "")
        return await cls._backend.clear(namespace, key)
